#[derive(Debug, Clone)]
struct BroadcastTicket {
    session_id: u64,
    contribution_id: u64,
    kind: BroadcastTurnKind,
    topic: String,
    subtopic: String,
    role: CourtRole,
    prior_speaker: String,
    prior_text: String,
    assignment: String,
    source_cards: String,
    retry_count: u8,
}

impl BroadcastTicket {
    fn prompt(&self) -> String {
        let source_cards = if self.source_cards.trim().is_empty() {
            "No verified source card is attached. Do not invent an incident, quotation, statistic, citation, or source; state uncertainty where it matters."
                .to_string()
        } else {
            format!(
                "VERIFIED SOURCE CARDS (use only what is relevant):\n{}",
                self.source_cards
            )
        };
        let length = if self.kind == BroadcastTurnKind::MusicBridge {
            "Speak only 12-30 words as a crisp verbal bridge over the already-playing bed."
        } else {
            "Speak 45-105 words in 2-4 complete spoken sentences."
        };
        let topic_contract = if self.kind == BroadcastTurnKind::HostOpening {
            format!(
                "OPENING SUBJECT (establish it once, naturally): {}",
                self.topic
            )
        } else {
            format!(
                "LOCKED TOPIC KEYWORDS (every claim must stay anchored to at least one of these; never announce or restate the show's theme): {} — current segment: {}\nCONTINUITY: Infer the established subject from the exact prior contribution and the current rundown segment. Do not announce, restate, summarize, or name the topic/theme again. Continue directly from the prior speaker and the current argument.",
                broadcast_topic_keywords(&self.topic).join(", "),
                self.subtopic
            )
        };
        let persona = if self.role == CourtRole::Queen {
            "\nQUEEN PERSONA: Speak in a theatrical, opinionated, playful, first-person perspective as Teledra's Sovereign Queen."
        } else {
            ""
        };
        format!(
            "BROADCAST CONTRIBUTION CONTRACT\nSession: {}\nContribution: {}\n{}\nRundown segment: {}\nTurn: {}\nTeledra/current prior speaker: {}\nEXACT PRIOR CONTRIBUTION (do not repeat or lightly paraphrase it):\n\"\"\"{}\"\"\"\n\nYOUR EXPLICIT ASSIGNMENT: {}\n\n{}{}\n\n{} Speak as if the audience heard every earlier turn. Do not introduce yourself, imitate another role, quote more than six consecutive words from the prior contribution, summarize the whole show, or emit any hidden/action/tool/delegation tag. Add one genuinely new mechanism, fact, consequence, qualification, objection, or transition.",
            self.session_id,
            self.contribution_id,
            topic_contract,
            self.subtopic,
            self.kind.label(),
            self.prior_speaker,
            self.prior_text,
            self.assignment,
            source_cards,
            persona,
            length,
        )
    }
}

#[derive(Debug)]
struct BroadcastSession {
    id: u64,
    topic: String,
    started_at: Instant,
    deadline: Instant,
    next_due: Instant,
    contribution_index: u64,
    next_kind: BroadcastTurnKind,
    current_subtopic: String,
    turn_in_flight: bool,
    tick_armed: bool,
    awaiting_speech: bool,
    on_air_role: Option<CourtRole>,
    on_air_speaking: bool,
    panelists_in_segment: u8,
    counterpoint_cursor: u64,
    last_host_claim: String,
    pending_panel: Option<(CourtRole, String)>,
    last_contribution: Option<(CourtRole, String)>,
    last_chat_prompt: Instant,
    last_source_check: Instant,
    last_music_bridge: Instant,
    last_completed_kind: Option<BroadcastTurnKind>,
    finishing: bool,
}

impl BroadcastSession {
    fn new(id: u64, topic: String, now: Instant) -> Self {
        Self {
            id,
            topic,
            started_at: now,
            deadline: now + Duration::from_secs(BROADCAST_DURATION_SECS),
            next_due: now,
            contribution_index: 0,
            next_kind: BroadcastTurnKind::HostOpening,
            current_subtopic: BROADCAST_RUNDOWN[0].1.to_string(),
            turn_in_flight: false,
            tick_armed: false,
            awaiting_speech: false,
            on_air_role: None,
            on_air_speaking: false,
            panelists_in_segment: 0,
            counterpoint_cursor: 0,
            last_host_claim: String::new(),
            pending_panel: None,
            last_contribution: None,
            last_chat_prompt: now,
            last_source_check: now,
            last_music_bridge: now,
            last_completed_kind: None,
            finishing: false,
        }
    }

    fn elapsed_secs(&self, now: Instant) -> u64 {
        now.saturating_duration_since(self.started_at).as_secs()
    }

    fn remaining_secs(&self, now: Instant) -> u64 {
        self.deadline.saturating_duration_since(now).as_secs()
    }
}

impl CourtDelegation {
    fn untracked(role: CourtRole, instruction: impl Into<String>) -> Self {
        Self {
            role,
            instruction: instruction.into(),
            mission_task_id: None,
        }
    }
}

fn organist_command_requires_score(instruction: &str) -> bool {
    let lower = instruction.to_ascii_lowercase();
    let mutating = [
        "compose",
        "create",
        "generate",
        "write a song",
        "write a track",
        "make music",
        "make a track",
        "change",
        "edit",
        "evolve",
        "replace",
        "remix",
        "reharmon",
        "rearrange",
        "improvise",
        "new song",
        "new track",
        "new tune",
        "new score",
        "apply this",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    if mutating {
        return true;
    }

    let names_current_surface = ["current", "existing", "canonical", "already"]
        .iter()
        .any(|needle| lower.contains(needle));
    let playback_or_description = ["open", "play", "listen", "describe", "show", "status"]
        .iter()
        .any(|needle| lower.contains(needle));
    if names_current_surface && playback_or_description {
        return false;
    }

    let study_only = [
        "research",
        "study",
        "learn",
        "explain",
        "analyse",
        "analyze",
        "audit",
        "review",
        "music theory",
    ]
    .iter()
    .any(|needle| lower.contains(needle));
    !study_only
}

