const BROADCAST_RUNDOWN: [(u64, &str); 8] = [
    (0, "Opening thesis"),
    (10 * 60, "What changes for the actors involved"),
    (25 * 60, "Risks, incentives, and defenses"),
    (40 * 60, "Evidence and real-world grounding"),
    (60 * 60, "Court disagreement"),
    (80 * 60, "Audience questions"),
    (100 * 60, "Practical advice"),
    (115 * 60, "Closing judgment"),
];

fn broadcast_rundown_index(elapsed_secs: u64) -> usize {
    BROADCAST_RUNDOWN
        .iter()
        .rposition(|(offset, _)| elapsed_secs >= *offset)
        .unwrap_or(0)
}

fn broadcast_rundown_text(topic: &str) -> String {
    let rows = BROADCAST_RUNDOWN
        .iter()
        .map(|(seconds, title)| {
            format!(
                "{:02}:{:02}  {}",
                seconds / 3600,
                (seconds % 3600) / 60,
                title
            )
        })
        .collect::<Vec<_>>()
        .join("\n");
    format!(
        "COURT RADIO // 120-minute topic lock\nTopic: {}\n{}",
        topic, rows
    )
}

fn broadcast_interval_seconds(topic: &str, contribution_index: u64) -> u64 {
    // Stable FNV-1a instead of a process-randomized hasher: the same session
    // plan is reproducible in tests and post-show audits.
    let mut hash = 0xcbf29ce484222325u64;
    for byte in topic
        .as_bytes()
        .iter()
        .copied()
        .chain(contribution_index.to_le_bytes())
    {
        hash ^= u64::from(byte);
        hash = hash.wrapping_mul(0x100000001b3);
    }
    let span = BROADCAST_MAX_TURN_INTERVAL_SECS - BROADCAST_MIN_TURN_INTERVAL_SECS + 1;
    BROADCAST_MIN_TURN_INTERVAL_SECS + hash % span
}

/// Court Radio owns the audible foreground for the lifetime of its tokened
/// session. Ordinary court speech has no session id and must remain off air;
/// a queued broadcast contribution is admissible only for the current session.
fn foreground_speech_is_admitted(
    active_broadcast_session_id: Option<u64>,
    speech_session_id: Option<u64>,
) -> bool {
    match active_broadcast_session_id {
        Some(active_id) => speech_session_id == Some(active_id),
        None => speech_session_id.is_none(),
    }
}

fn format_broadcast_clock(seconds: u64) -> String {
    format!("{:02}:{:02}", seconds / 3600, (seconds % 3600) / 60)
}

fn format_broadcast_countdown(seconds: u64) -> String {
    format!("{:02}:{:02}", seconds / 60, seconds % 60)
}

fn queen_requests_counterpoint(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    [
        "delegates, what say you",
        "delegates what say you",
        "ministers, what say you",
        "who disagrees",
        "prove me wrong",
        "poke holes",
        "give me a counterpoint",
        "counterpoint",
        "what does the court say",
        "court, respond",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
}

fn route_broadcast_counterpoint(topic: &str, claim: &str, cursor: u64) -> CourtRole {
    let lower = format!("{} {}", topic, claim).to_ascii_lowercase();
    if [
        "evidence",
        "source",
        "incident",
        "statistic",
        "definition",
        "fact",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
    {
        CourtRole::Scribe
    } else if [
        "code",
        "technical",
        "mechanism",
        "security",
        "attack",
        "defense",
        "system",
        "model",
        "algorithm",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        && cursor % 3 != 2
    {
        CourtRole::Alchemist
    } else if [
        "society",
        "people",
        "trust",
        "policy",
        "law",
        "work",
        "community",
        "incentive",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        && cursor % 3 != 2
    {
        CourtRole::Diplomat
    } else if [
        "art",
        "visual",
        "design",
        "layout",
        "aesthetic",
        "color",
        "render",
        "image",
        "palette",
    ]
    .iter()
    .any(|needle| lower.contains(needle))
        && cursor % 3 != 2
    {
        CourtRole::Artist
    } else {
        CourtRole::Malthus
    }
}

fn next_broadcast_kind_after_reaction(
    session: &BroadcastSession,
    now: Instant,
) -> BroadcastTurnKind {
    if session.panelists_in_segment < BROADCAST_MAX_PANELISTS_PER_SEGMENT {
        return BroadcastTurnKind::Counterpoint;
    }
    let deadlines = [
        (
            session.last_music_bridge + Duration::from_secs(BROADCAST_MUSIC_BRIDGE_SECS),
            BroadcastTurnKind::MusicBridge,
        ),
        (
            session.last_chat_prompt + Duration::from_secs(BROADCAST_CHAT_PROMPT_SECS),
            BroadcastTurnKind::AudienceQuestion,
        ),
        (
            session.last_source_check + Duration::from_secs(BROADCAST_SOURCE_CHECK_SECS),
            BroadcastTurnKind::FactCheck,
        ),
    ];
    deadlines
        .iter()
        .filter(|(deadline, _)| now >= *deadline)
        .min_by_key(|(deadline, _)| *deadline)
        .map(|(_, kind)| *kind)
        .unwrap_or(BroadcastTurnKind::NextSubtopic)
}

fn recent_broadcast_source_cards(topic: &str) -> String {
    let Ok(contents) = std::fs::read_to_string(RESEARCH_BRIEFS_PATH) else {
        return String::new();
    };
    let keywords = topic
        .split(|character: char| !character.is_alphanumeric())
        .map(str::to_ascii_lowercase)
        .filter(|word| word.len() >= 4)
        .collect::<Vec<_>>();
    let mut cards = Vec::new();
    for line in contents.lines().rev().take(160) {
        let Ok(value) = serde_json::from_str::<serde_json::Value>(line) else {
            continue;
        };
        if !value
            .get("usable")
            .and_then(|v| v.as_bool())
            .unwrap_or(false)
        {
            continue;
        }
        let searchable = line.to_ascii_lowercase();
        if !keywords.is_empty() && !keywords.iter().any(|word| searchable.contains(word)) {
            continue;
        }
        let Some(claim) = value
            .get("claims")
            .and_then(|claims| claims.as_array())
            .and_then(|claims| claims.first())
            .and_then(|claim| claim.get("statement"))
            .and_then(|statement| statement.as_str())
        else {
            continue;
        };
        let source = value
            .get("sources")
            .and_then(|sources| sources.as_array())
            .and_then(|sources| sources.first());
        let title = source
            .and_then(|source| source.get("title"))
            .and_then(|title| title.as_str())
            .unwrap_or("Grounded research brief");
        let url = source
            .and_then(|source| source.get("url"))
            .and_then(|url| url.as_str())
            .unwrap_or("");
        cards.push(format!(
            "- {} — {}{}",
            truncate_chars(claim, 360),
            title,
            if url.is_empty() {
                String::new()
            } else {
                format!(" ({})", url)
            }
        ));
        if cards.len() == 2 {
            break;
        }
    }
    cards.reverse();
    cards.join("\n")
}

fn build_broadcast_ticket(session: &mut BroadcastSession, now: Instant) -> BroadcastTicket {
    let rundown_index = broadcast_rundown_index(session.elapsed_secs(now));
    let subtopic = BROADCAST_RUNDOWN[rundown_index].1.to_string();
    session.current_subtopic = subtopic.clone();
    let kind = if now >= session.deadline {
        BroadcastTurnKind::Closing
    } else {
        session.next_kind
    };

    let (role, prior_speaker, prior_text, assignment) = match kind {
        BroadcastTurnKind::HostOpening => (
            CourtRole::Queen,
            "Broadcast producer".to_string(),
            session.topic.clone(),
            "Open with a substantial, vivid thesis and frame the stakes. Establish one arguable claim, preview the Court's disagreement, and invite a real counterpoint without wrapping up the topic.".to_string(),
        ),
        BroadcastTurnKind::Counterpoint => {
            let role = route_broadcast_counterpoint(
                &session.topic,
                &session.last_host_claim,
                session.counterpoint_cursor,
            );
            session.counterpoint_cursor = session.counterpoint_cursor.saturating_add(1);
            let mut assignment = match role {
                CourtRole::Scribe => "Act as the factual desk, not an archivist. Challenge one evidentiary weakness: define one relevant term, distinguish verified fact from inference, and do not invent a source, incident, number, or quotation.".to_string(),
                CourtRole::Alchemist => "Translate the host's metaphor into a causal technical mechanism. Give one concrete defensive or practical example, then identify one limitation. Your first sentence must clearly qualify or disagree with the host.".to_string(),
                CourtRole::Diplomat => "Challenge the host from stakeholder, incentive, trust, jurisdiction, or social-consequence angles. Give one alternate perspective and one consequence the host has missed. Do not perform outreach.".to_string(),
                CourtRole::Artist => "Challenge the host from a visual design, aesthetics, layout, color palette, or user experience perspective. Focus on how form, structure, or interface elements influence human perception and engagement.".to_string(),
                CourtRole::Malthus => "Attack the strongest hidden assumption with a plausible high-level failure mode and one uncomfortable question. Your first sentence must clearly disagree or qualify. Keep any mischief bounded and non-operational.".to_string(),
                _ => "Give a genuine, specific counterpoint and one new consequence the host must answer.".to_string(),
            };
            // Keywords, not the verbatim theme: priming the full title makes the
            // 7B re-announce it; the overlap validator only needs the words.
            assignment.push_str(&format!(
                " Relate this directly to: {}.",
                broadcast_topic_keywords(&session.topic).join(", ")
            ));
            (
                role,
                "Teledra".to_string(),
                session.last_host_claim.clone(),
                assignment,
            )
        }
        BroadcastTurnKind::HostReaction => {
            let (panel_role, panel_text) = session
                .pending_panel
                .clone()
                .unwrap_or((CourtRole::Malthus, "The Court's objection was lost in static.".to_string()));
            (
                CourtRole::Queen,
                panel_role.as_str().to_string(),
                panel_text,
                format!(
                    "Answer {}'s strongest point by name in the first sentence: concede, rebut, or complicate it. Then synthesize one useful idea and advance the argument. Do not thank them, recap the show, or evade the objection.",
                    panel_role.as_str()
                ),
            )
        }
        BroadcastTurnKind::FactCheck => (
            CourtRole::Scribe,
            "Teledra".to_string(),
            session.last_host_claim.clone(),
            "Run a spoken source-desk insert, not an archive action. Use only an attached verified source card. If none is attached, name the exact uncertainty that still needs checking instead of manufacturing facts.".to_string(),
        ),
        BroadcastTurnKind::AudienceQuestion => (
            CourtRole::Queen,
            session
                .last_contribution
                .as_ref()
                .map(|(role, _)| role.as_str())
                .unwrap_or("Court")
                .to_string(),
            session
                .last_contribution
                .as_ref()
                .map(|(_, text)| text.clone())
                .unwrap_or_else(|| session.last_host_claim.clone()),
            "Turn the current disagreement into one precise audience question. Briefly explain why the answer matters, invite chat to test the Court's premise, and leave room for the next correspondent.".to_string(),
        ),
        BroadcastTurnKind::MusicBridge => (
            CourtRole::Organist,
            "Teledra".to_string(),
            session.last_host_claim.clone(),
            "Act as music director, not composer. Give a short atmospheric verbal bridge (tension, reveal, breath, or return) over the already-playing keeper. Do not emit or request a CourtScore and do not claim the bed changed.".to_string(),
        ),
        BroadcastTurnKind::NextSubtopic => (
            CourtRole::Queen,
            session
                .last_contribution
                .as_ref()
                .map(|(role, _)| role.as_str())
                .unwrap_or("Court")
                .to_string(),
            session
                .last_contribution
                .as_ref()
                .map(|(_, text)| text.clone())
                .unwrap_or_else(|| session.last_host_claim.clone()),
            format!(
                "Bridge naturally into the rundown chapter '{}'. State one fresh, arguable claim rather than announcing a schedule, then invite one relevant Court voice to challenge it.",
                subtopic
            ),
        ),
        BroadcastTurnKind::Closing => (
            CourtRole::Queen,
            session
                .last_contribution
                .as_ref()
                .map(|(role, _)| role.as_str())
                .unwrap_or("Court")
                .to_string(),
            session
                .last_contribution
                .as_ref()
                .map(|(_, text)| text.clone())
                .unwrap_or_else(|| session.last_host_claim.clone()),
            "Deliver the closing judgment: name the strongest conclusion, the most important unresolved uncertainty, one practical takeaway, and a final Teledra flourish. Do not start another thread.".to_string(),
        ),
    };

    BroadcastTicket {
        session_id: session.id,
        contribution_id: session.contribution_index.saturating_add(1),
        kind,
        topic: session.topic.clone(),
        subtopic,
        role,
        prior_speaker,
        prior_text,
        assignment,
        source_cards: if kind == BroadcastTurnKind::FactCheck {
            recent_broadcast_source_cards(&session.topic)
        } else {
            String::new()
        },
        retry_count: 0,
    }
}

fn accept_broadcast_contribution(
    session: &mut BroadcastSession,
    ticket: &BroadcastTicket,
    visible: &str,
    now: Instant,
) {
    session.contribution_index = ticket.contribution_id;
    session.turn_in_flight = false;
    session.awaiting_speech = true;
    session.on_air_role = Some(ticket.role);
    session.on_air_speaking = false;
    session.last_completed_kind = Some(ticket.kind);
    session.last_contribution = Some((ticket.role, visible.to_string()));
    match ticket.kind {
        BroadcastTurnKind::HostOpening => {
            session.last_host_claim = visible.to_string();
            session.next_kind = BroadcastTurnKind::Counterpoint;
        }
        BroadcastTurnKind::Counterpoint | BroadcastTurnKind::FactCheck => {
            session.pending_panel = Some((ticket.role, visible.to_string()));
            session.panelists_in_segment = session
                .panelists_in_segment
                .saturating_add(1)
                .min(BROADCAST_MAX_PANELISTS_PER_SEGMENT);
            session.next_kind = BroadcastTurnKind::HostReaction;
            if ticket.kind == BroadcastTurnKind::FactCheck {
                session.last_source_check = now;
            }
        }
        BroadcastTurnKind::HostReaction => {
            session.last_host_claim = visible.to_string();
            session.pending_panel = None;
            session.panelists_in_segment = 0;
            session.next_kind = next_broadcast_kind_after_reaction(session, now);
        }
        BroadcastTurnKind::AudienceQuestion => {
            session.last_host_claim = visible.to_string();
            session.last_chat_prompt = now;
            session.next_kind = BroadcastTurnKind::Counterpoint;
        }
        BroadcastTurnKind::MusicBridge => {
            session.last_music_bridge = now;
            session.next_kind = BroadcastTurnKind::NextSubtopic;
        }
        BroadcastTurnKind::NextSubtopic => {
            session.last_host_claim = visible.to_string();
            session.next_kind = BroadcastTurnKind::Counterpoint;
        }
        BroadcastTurnKind::Closing => {
            session.last_host_claim = visible.to_string();
            session.finishing = true;
        }
    }
    if ticket.role == CourtRole::Queen
        && ticket.kind != BroadcastTurnKind::Closing
        && queen_requests_counterpoint(visible)
    {
        session.next_kind = BroadcastTurnKind::Counterpoint;
    }
}

fn normalized_broadcast_words(text: &str) -> Vec<String> {
    text.split_whitespace()
        .map(|word| {
            word.chars()
                .filter(|character| character.is_alphanumeric())
                .flat_map(char::to_lowercase)
                .collect::<String>()
        })
        .filter(|word| !word.is_empty())
        .collect()
}

fn broadcast_reply_repeats_prior(candidate: &str, prior: &str) -> bool {
    let candidate_words = normalized_broadcast_words(candidate);
    let prior_words = normalized_broadcast_words(prior);
    if candidate_words.len() >= 8
        && prior_words.len() >= 8
        && candidate_words[..8] == prior_words[..8]
    {
        return true;
    }
    if candidate_words.len() < 12 || prior_words.len() < 12 {
        return false;
    }
    candidate_words.windows(12).any(|window| {
        prior_words
            .windows(12)
            .any(|prior_window| window == prior_window)
    })
}

fn broadcast_reannounces_locked_topic(text: &str) -> bool {
    let lower = text.to_ascii_lowercase();
    [
        "today's topic",
        "todays topic",
        "our topic",
        "the topic today",
        "the topic is",
        "our theme",
        "today's theme",
        "todays theme",
        "the theme is",
        "we are discussing",
        "we're discussing",
        "we are here to discuss",
        "back to our topic",
        "returning to the topic",
        "as we discuss",
    ]
    .iter()
    .any(|marker| lower.contains(marker))
}

fn counterpoint_has_contrast(text: &str) -> bool {
    let opening = text
        .split_whitespace()
        .take(18)
        .collect::<Vec<_>>()
        .join(" ")
        .to_ascii_lowercase();
    [
        "but",
        "however",
        "yet",
        "disagree",
        "not quite",
        "the weakness",
        "the trouble",
        "the hidden assumption",
        "except",
        "challenge",
        "overlooks",
        "misses",
    ]
    .iter()
    .any(|needle| opening.contains(needle))
}

fn trim_broadcast_words(text: &str, maximum: usize) -> String {
    let words = text.split_whitespace().collect::<Vec<_>>();
    if words.len() <= maximum {
        return text.trim().to_string();
    }
    let mut trimmed = words[..maximum].join(" ");
    trimmed = trimmed
        .trim_end_matches(|character: char| matches!(character, ',' | ';' | ':' | '-'))
        .to_string();
    if !trimmed.ends_with(['.', '!', '?']) {
        trimmed.push('.');
    }
    trimmed
}

fn strip_trailing_handoff(text: &str) -> String {
    let text = text.trim();
    let sentences: Vec<&str> = text.split_inclusive(|c| c == '.' || c == '!' || c == '?').collect();
    if sentences.is_empty() {
        return text.to_string();
    }
    let last = sentences.last().unwrap().trim().to_lowercase();
    let contains_handoff = ["back to teledra", "hand back", "over to you", "back to you", "handing back", "over to teledra"]
        .iter()
        .any(|phrase| last.contains(phrase));

    if contains_handoff {
        let mut result = String::new();
        for &s in &sentences[..sentences.len() - 1] {
            result.push_str(s);
        }
        result.trim().to_string()
    } else {
        text.to_string()
    }
}

fn strip_broadcast_action_tags(text: &str) -> String {
    let mut cleaned = text.to_string();
    for prefix in [
        "[DELEGATE:",
        "[RESEARCH:",
        "[SUGGESTION:",
        "[DIPLOMACY:",
        "[TOPIC:",
        "[CONDUCT:",
        "[SCRIBE_WRITE:",
        "[SCRIBE_APPEND:",
        "[PYTHON_MUSIC:",
        "[STRUDEL_MUSIC:",
        "[PYTHON_ART:",
        "[FRACTUS_ART:",
        "[FRACTUS_LIVE:",
        "[WORKSHOP_TOOL:",
        "[TASTE:",
        "[DESIRE:",
        "[OPINION:",
        "[CURIOSITY:",
    ] {
        while let Some((next, _)) = extract_tag_content(&cleaned, prefix) {
            cleaned = next;
        }
    }
    while let Some((next, _)) = extract_court_score_tag(&cleaned) {
        cleaned = next;
    }
    for exact in ["[UNLOCK]", "[STOP_BABBLE]", "[CLOSE_ART]", "[STOP_ART]"] {
        cleaned = cleaned.replace(exact, "");
    }
    let stripped = strip_unclosed_tool_and_code_noise(&cleaned);
    strip_trailing_handoff(&stripped)
}

fn current_unix_timestamp() -> String {
    match std::time::SystemTime::now().duration_since(std::time::UNIX_EPOCH) {
        Ok(d) => d.as_secs().to_string(),
        Err(_) => "0".to_string(),
    }
}

fn current_unix_timestamp_ns() -> u64 {
    std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .ok()
        .and_then(|duration| u64::try_from(duration.as_nanos()).ok())
        .unwrap_or(0)
}

#[derive(Clone, Copy, Debug, PartialEq, Eq, serde::Deserialize, serde::Serialize)]
#[serde(rename_all = "snake_case")]
enum HumanMusicFeedbackDecision {
    LikeAsIs,
    LikeWorkOnIt,
    Dislike,
    DislikeWorkOnIt,
}

impl HumanMusicFeedbackDecision {
    fn requests_work(self) -> bool {
        matches!(
            self,
            Self::LikeWorkOnIt | Self::Dislike | Self::DislikeWorkOnIt
        )
    }

    fn preserves_keeper_identity(self) -> bool {
        matches!(self, Self::LikeWorkOnIt | Self::DislikeWorkOnIt)
    }

    /// Work-on-it votes preserve the exact heard artifact as a workshop source.
    /// They no longer authorize an immediate replacement of the live score.
    fn routes_to_back_workshop(self) -> bool {
        self.preserves_keeper_identity()
    }

    /// An explicit as-is keeper starts a bounded listening lease. A newly
    /// installed, unrated result is protected separately by
    /// `HumanMusicHold::awaiting_review` until it receives its own verdict.
    fn starts_keeper_lease(self) -> bool {
        matches!(self, Self::LikeAsIs)
    }

    fn label(self) -> &'static str {
        match self {
            Self::LikeAsIs => "like as-is",
            Self::LikeWorkOnIt => "like, but work on it",
            Self::Dislike => "dislike and replace",
            Self::DislikeWorkOnIt => "dislike, but work on it",
        }
    }
}

#[derive(Clone, Debug, serde::Deserialize, serde::Serialize)]
struct HumanMusicFeedback {
    schema_version: u64,
    kind: String,
    event_id: String,
    decision: HumanMusicFeedbackDecision,
    project_id: String,
    score_revision: u64,
    score_sha256: String,
    #[serde(default)]
    wav_sha256: String,
    #[serde(default)]
    renderer_score_sha256: String,
    #[serde(default)]
    created_at: String,
    #[serde(default)]
    created_at_unix_ns: u64,
    #[serde(default)]
    action: serde_json::Value,
    #[serde(default)]
    features: serde_json::Value,
    #[serde(default)]
    verification: serde_json::Value,
    #[serde(default)]
    artifacts: serde_json::Value,
}

#[derive(Clone, Debug, serde::Deserialize, serde::Serialize, PartialEq, Eq)]
struct HumanMusicScoreTarget {
    project_id: String,
    score_revision: u64,
    score_sha256: String,
}

impl HumanMusicScoreTarget {
    fn from_feedback(feedback: &HumanMusicFeedback) -> Self {
        Self {
            project_id: feedback.project_id.clone(),
            score_revision: feedback.score_revision,
            score_sha256: feedback.score_sha256.to_ascii_lowercase(),
        }
    }
}

#[derive(Clone, Debug, serde::Deserialize, serde::Serialize)]
struct HumanMusicHold {
    event_id: String,
    decision: HumanMusicFeedbackDecision,
    target: HumanMusicScoreTarget,
    /// True when the live front-stage result has not received its own verdict,
    /// or when a workshop source could not yet be parked safely. The result is
    /// protected but must never inherit the earlier artifact's vote.
    #[serde(default)]
    awaiting_review: bool,
    /// Wall-clock deadline so a restart cannot turn a ten-minute listening
    /// lease into an immortal pin. Older state derives the deadline from the
    /// exact feedback event and fails closed only when that timestamp is absent.
    #[serde(default)]
    lease_expires_unix_ns: u64,
}

#[derive(Clone, Debug, serde::Deserialize, serde::Serialize)]
struct HumanMusicFeedbackState {
    schema_version: u64,
    epoch: u64,
    #[serde(default)]
    processed_event_ids: Vec<String>,
    #[serde(default)]
    hold: Option<HumanMusicHold>,
    #[serde(default)]
    pending: Option<HumanMusicFeedback>,
    #[serde(default)]
    latest_feedback: Option<HumanMusicFeedback>,
}

impl Default for HumanMusicFeedbackState {
    fn default() -> Self {
        Self {
            schema_version: 1,
            epoch: 0,
            processed_event_ids: Vec::new(),
            hold: None,
            pending: None,
            latest_feedback: None,
        }
    }
}

impl HumanMusicFeedbackState {
    fn mark_processed(&mut self, event_id: &str) {
        if !self.processed_event_ids.iter().any(|item| item == event_id) {
            self.processed_event_ids.push(event_id.to_string());
        }
        if self.processed_event_ids.len() > 512 {
            let excess = self.processed_event_ids.len() - 512;
            self.processed_event_ids.drain(0..excess);
        }
    }
}

