/// Expand every deterministic fallback into a real long-form arrangement.
/// Eight eight-bar chapters give the arranger enough room for statement,
/// answer, subtraction, arrival, return, and release while remaining safely
/// above two minutes at every supported Court Synth tempo (up to 128 BPM).
fn canonicalize_long_form_sections(style: &str, sections: &mut serde_json::Value) {
    let Some(items) = sections.as_array_mut() else {
        return;
    };
    items.truncate(8);
    for section in items.iter_mut() {
        if let Some(object) = section.as_object_mut() {
            object.insert("bars".to_string(), serde_json::json!(8));
        }
    }

    let closing_chapters: &[(&str, f64, &str)] = match style {
        "spicy_lofi" => &[
            ("midnight_walk", 0.56, "forward"),
            ("ember_bloom", 0.82, "call_response"),
            ("lantern_return", 0.60, "recombine"),
            ("afterglow", 0.34, "fragment"),
        ],
        "court_experimental" => &[
            ("orbit", 0.52, "sequence"),
            ("convergence_field", 0.88, "call_response"),
            ("residue_return", 0.46, "recombine"),
            ("afterimage", 0.30, "fragment"),
        ],
        _ => &[
            ("distant_map", 0.54, "forward"),
            ("final_ascent", 0.86, "sequence"),
            ("homeward", 0.44, "recombine"),
            ("epilogue", 0.28, "fragment"),
        ],
    };
    for &(name, energy, transform) in closing_chapters {
        if items.len() >= 8 {
            break;
        }
        let already_present = items
            .iter()
            .any(|section| section.get("name").and_then(|value| value.as_str()) == Some(name));
        if !already_present {
            items.push(serde_json::json!({
                "name": name,
                "bars": 8,
                "energy": energy,
                "transform": transform
            }));
        }
    }
}

