#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum StrudelLaunchMode {
    CyberneticSynthesizer,
    LegacyJavaSketchpad,
}

impl StrudelLaunchMode {
    fn label(self) -> &'static str {
        match self {
            Self::CyberneticSynthesizer => "Court Cybernetic Synthesizer",
            Self::LegacyJavaSketchpad => "legacy Java Strudel Sketchpad",
        }
    }
}

fn strudel_launch_order(
    cybernetic_synth_available: bool,
    legacy_java_available: bool,
) -> Result<Vec<StrudelLaunchMode>, String> {
    let mut order = Vec::new();
    if cybernetic_synth_available {
        order.push(StrudelLaunchMode::CyberneticSynthesizer);
    }
    if legacy_java_available {
        order.push(StrudelLaunchMode::LegacyJavaSketchpad);
    }
    if order.is_empty() {
        Err(
            "No Strudel playback surface is installed: the local Cybernetic Synthesizer and legacy Java Sketchpad are both unavailable."
                .to_string(),
        )
    } else {
        Ok(order)
    }
}

fn build_strudel_command(mode: StrudelLaunchMode) -> Command {
    let mut command = match mode {
        StrudelLaunchMode::CyberneticSynthesizer => {
            let mut command = Command::new("node.exe");
            // Force Windows default routing on code level so the native synth follows
            // the same audio channel/bus the user has selected in Windows Sound / RØDE UNIFY.
            // This makes panned instruments and all layers route consistently with default audio.
            // Also anchor the Tk window (small) to bottom-right so it doesn't hide Fractus.
            command
                .env("TELEDRA_AUDIO_DEVICE", "default")
                .env("TELEDRA_AUDIO_HOSTAPI", "MME")
                .env("TELEDRA_WINDOW_GEOMETRY", "980x400+50+700")
                .arg(LOCAL_STRUDEL_APP_PATH)
                .arg("play")
                .arg("8")
                .current_dir("D:\\Teledra");
            command
        }
        StrudelLaunchMode::LegacyJavaSketchpad => {
            let mut command = Command::new("cmd.exe");
            command
                .arg("/C")
                .arg("run.bat")
                .arg("D:\\Teledra\\strudel_app\\current.strudel")
                .current_dir(LEGACY_STRUDEL_DIR);
            command
        }
    };
    command.stdout(Stdio::null()).stderr(Stdio::null());
    hide_console(&mut command);
    command
}

fn stop_strudel_tool_processes() -> usize {
    stop_tool_processes(STRUDEL_PROCESS_MARKERS, STRUDEL_PROCESS_NAMES)
}

fn is_court_score_code(code: &str) -> bool {
    let trimmed = strip_fenced_code_block(code, "json");
    trimmed.starts_with('{')
        && serde_json::from_str::<serde_json::Value>(&trimmed)
            .ok()
            .and_then(|value| value.get("schema_version").and_then(|v| v.as_u64()))
            .map(|version| version == 1 || version == 2)
            .unwrap_or(false)
}

fn normalized_court_score_code(code: &str) -> String {
    strip_fenced_code_block(code, "json")
}

fn validate_court_score_code(code: &str) -> Result<(), String> {
    let cleaned = normalized_court_score_code(code);
    let parsed: serde_json::Value = serde_json::from_str(&cleaned)
        .map_err(|error| format!("CourtScore must be valid JSON: {error}"))?;
    let schema_version = parsed
        .get("schema_version")
        .and_then(|value| value.as_u64());
    if schema_version != Some(1) && schema_version != Some(2) {
        return Err("CourtScore must declare schema_version 1 or 2.".to_string());
    }
    let nonce = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or(0);
    let tmp_path = format!(
        "D:\\Teledra\\court_synth\\__validate_{}_{}.json",
        std::process::id(),
        nonce
    );
    std::fs::create_dir_all("D:\\Teledra\\court_synth")
        .map_err(|error| format!("Could not prepare Court Synth project folder: {error}"))?;
    std::fs::write(&tmp_path, cleaned)
        .map_err(|error| format!("Could not stage CourtScore validation: {error}"))?;
    let mut command = Command::new(LOCAL_STRUDEL_PYTHON_PATH);
    command
        .arg(COURT_SYNTH_SCRIPT_PATH)
        .arg("validate")
        .arg(&tmp_path)
        .current_dir("D:\\Teledra")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    hide_console(&mut command);
    let output = command
        .output()
        .map_err(|error| format!("Could not run Court Synth validator: {error}"))?;
    let _ = std::fs::remove_file(&tmp_path);
    if output.status.success() {
        Ok(())
    } else {
        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
        let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
        Err(if stderr.is_empty() { stdout } else { stderr })
    }
}

fn normalize_court_score_harmony(code: &str, source_code: Option<&str>) -> Result<String, String> {
    let nonce = std::time::SystemTime::now()
        .duration_since(std::time::UNIX_EPOCH)
        .map(|duration| duration.as_nanos())
        .unwrap_or(0);
    let base = format!(
        "D:\\Teledra\\court_synth\\__normalize_{}_{}",
        std::process::id(),
        nonce
    );
    let score_path = format!("{base}.json");
    let source_path = format!("{base}_source.json");
    std::fs::create_dir_all("D:\\Teledra\\court_synth")
        .map_err(|error| format!("Could not prepare Court Synth normalization: {error}"))?;
    std::fs::write(&score_path, normalized_court_score_code(code))
        .map_err(|error| format!("Could not stage CourtScore normalization: {error}"))?;
    if let Some(source) = source_code {
        if let Err(error) = std::fs::write(&source_path, normalized_court_score_code(source)) {
            let _ = std::fs::remove_file(&score_path);
            return Err(format!("Could not stage the source harmony: {error}"));
        }
    }
    let mut command = Command::new(LOCAL_STRUDEL_PYTHON_PATH);
    command
        .arg(COURT_SYNTH_SCRIPT_PATH)
        .arg("normalize")
        .arg(&score_path)
        .current_dir("D:\\Teledra")
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    if source_code.is_some() {
        command.arg("--source-score").arg(&source_path);
    }
    hide_console(&mut command);
    let output = command
        .output()
        .map_err(|error| format!("Could not run Court Synth harmony normalization: {error}"));
    let _ = std::fs::remove_file(&score_path);
    let _ = std::fs::remove_file(&source_path);
    let output = output?;
    if !output.status.success() {
        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
        let stdout = String::from_utf8_lossy(&output.stdout).trim().to_string();
        return Err(if stderr.is_empty() { stdout } else { stderr });
    }
    let stdout = String::from_utf8(output.stdout)
        .map_err(|error| format!("Court Synth normalizer returned non-UTF8 output: {error}"))?;
    let parsed: serde_json::Value = serde_json::from_str(stdout.trim())
        .map_err(|error| format!("Court Synth normalizer returned invalid JSON: {error}"))?;
    serde_json::to_string_pretty(&parsed)
        .map_err(|error| format!("Could not serialize normalized CourtScore: {error}"))
}

fn atomic_write_court_score(path: &Path, content: &str) -> Result<(), String> {
    let tmp_path =
        std::path::PathBuf::from(format!("{}.tmp.{}", path.display(), std::process::id()));
    std::fs::write(&tmp_path, content)
        .map_err(|error| format!("Could not stage CourtScore: {error}"))?;
    std::fs::rename(&tmp_path, path).map_err(|error| {
        let _ = std::fs::remove_file(&tmp_path);
        format!("Could not atomically install CourtScore: {error}")
    })
}

fn install_court_score(code: &str) -> Result<String, String> {
    let cleaned = normalized_court_score_code(code);
    validate_court_score_code(&cleaned)?;
    install_court_score_validated(&cleaned)
}

/// Install a CourtScore that has already passed the native Python gate in
/// this acceptance transaction. Existing/live content and the final merged
/// artifact are still revalidated around harmony normalization.
fn install_court_score_validated(cleaned: &str) -> Result<String, String> {
    let mut incoming: serde_json::Value = serde_json::from_str(&cleaned)
        .map_err(|error| format!("CourtScore must be valid JSON: {error}"))?;
    std::fs::create_dir_all("D:\\Teledra\\court_synth")
        .map_err(|error| format!("Could not create Court Synth project folder: {error}"))?;

    let mut normalization_source: Option<String> = None;
    if let Ok(existing_text) = std::fs::read_to_string(COURT_SYNTH_SCORE_PATH) {
        validate_court_score_code(&existing_text).map_err(|error| {
            format!("Refusing to replace the current invalid CourtScore: {error}")
        })?;
        let existing: serde_json::Value = serde_json::from_str(&existing_text)
            .map_err(|error| format!("Current CourtScore could not be read: {error}"))?;
        let existing_schema = existing
            .get("schema_version")
            .and_then(|value| value.as_u64())
            .unwrap_or(0);
        let incoming_schema = incoming
            .get("schema_version")
            .and_then(|value| value.as_u64())
            .unwrap_or(0);
        if existing_schema != incoming_schema {
            return Err(format!(
                "CourtScore schema change {} -> {} requires an explicit migration; the live project was left untouched.",
                existing_schema, incoming_schema
            ));
        }
        let base_revision = existing
            .get("revision")
            .and_then(|value| value.as_u64())
            .ok_or_else(|| "Current CourtScore has no valid revision.".to_string())?;
        let existing_project_id = existing
            .get("project_id")
            .cloned()
            .unwrap_or_else(|| serde_json::json!("court-synth-live"));

        let object = incoming
            .as_object_mut()
            .ok_or_else(|| "CourtScore root must be an object.".to_string())?;
        object.insert("project_id".to_string(), existing_project_id);
        object.insert("revision".to_string(), serde_json::json!(base_revision + 1));
        if existing_schema == 1 {
            object.insert(
                "manual_notes".to_string(),
                existing
                    .get("manual_notes")
                    .cloned()
                    .unwrap_or_else(|| serde_json::json!([])),
            );
        } else {
            if let (Some(incoming_tracks), Some(existing_tracks)) = (
                object
                    .get_mut("tracks")
                    .and_then(|value| value.as_array_mut()),
                existing.get("tracks").and_then(|value| value.as_array()),
            ) {
                for incoming_track in incoming_tracks {
                    let track_id = incoming_track.get("id").and_then(|value| value.as_str());
                    let Some(existing_track) = track_id.and_then(|id| {
                        existing_tracks.iter().find(|track| {
                            track.get("id").and_then(|value| value.as_str()) == Some(id)
                        })
                    }) else {
                        continue;
                    };
                    if let Some(track_object) = incoming_track.as_object_mut() {
                        for protected in ["clips", "mixer", "automation", "instrument"] {
                            if let Some(value) = existing_track.get(protected) {
                                track_object.insert(protected.to_string(), value.clone());
                            }
                        }
                    }
                }
            }
            if let Some(master) = existing.get("master") {
                object.insert("master".to_string(), master.clone());
            }
        }
        let lineage = object
            .entry("lineage".to_string())
            .or_insert_with(|| serde_json::json!({}));
        if let Some(lineage_object) = lineage.as_object_mut() {
            lineage_object.insert(
                "parent_revision".to_string(),
                serde_json::json!(base_revision),
            );
        }
        normalization_source = Some(existing_text);
    }

    let mut installed = serde_json::to_string_pretty(&incoming)
        .map_err(|error| format!("Could not serialize CourtScore: {error}"))?;
    if incoming
        .get("schema_version")
        .and_then(|value| value.as_u64())
        == Some(1)
    {
        installed = normalize_court_score_harmony(&installed, normalization_source.as_deref())?;
    }
    validate_court_score_code(&installed)?;
    atomic_write_court_score(Path::new(COURT_SYNTH_SCORE_PATH), &installed)?;
    Ok(installed)
}

fn load_or_bootstrap_court_score() -> Result<String, String> {
    match std::fs::read_to_string(COURT_SYNTH_SCORE_PATH) {
        Ok(score) => {
            validate_court_score_code(&score).map_err(|error| {
                format!("Current CourtScore is invalid and was not replaced: {error}")
            })?;
            Ok(normalized_court_score_code(&score))
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => {
            install_court_score(&default_court_score_code())
        }
        Err(error) => Err(format!("Could not read the current CourtScore: {error}")),
    }
}

fn existing_court_score_for_startup(
    path: &Path,
    music_enabled: bool,
    test_mode_enabled: bool,
) -> Result<Option<String>, String> {
    if !music_enabled || test_mode_enabled {
        return Ok(None);
    }
    match std::fs::read_to_string(path) {
        Ok(score) => {
            validate_court_score_code(&score).map_err(|error| {
                format!("Existing CourtScore is invalid and was not opened: {error}")
            })?;
            Ok(Some(normalized_court_score_code(&score)))
        }
        Err(error) if error.kind() == std::io::ErrorKind::NotFound => Ok(None),
        Err(error) => Err(format!("Could not read the existing CourtScore: {error}")),
    }
}

struct CourtSynthLaunchOutcome {
    message: String,
    score_changed: bool,
}

fn launch_court_synth(
    score: &str,
    active_process: &Arc<std::sync::Mutex<Option<std::process::Child>>>,
) -> Result<CourtSynthLaunchOutcome, String> {
    let cleaned = normalized_court_score_code(score);
    validate_court_score_code(&cleaned)?;
    launch_court_synth_validated(&cleaned, active_process)
}

fn launch_court_synth_validated(
    cleaned: &str,
    active_process: &Arc<std::sync::Mutex<Option<std::process::Child>>>,
) -> Result<CourtSynthLaunchOutcome, String> {
    let previous_score = std::fs::read_to_string(COURT_SYNTH_SCORE_PATH).ok();
    let score_changed = match previous_score.as_deref() {
        Some(existing) => {
            court_score_musical_fingerprint(existing)? != court_score_musical_fingerprint(&cleaned)?
        }
        None => true,
    };
    let stopped_legacy_python = stop_tool_processes(
        &[
            "python_music_editor.py",
            "D:\\Teledra\\python_music_editor.py",
            "D:\\Teledra\\music.py",
        ],
        &["python.exe", "pythonw.exe"],
    );
    let stopped_legacy_strudel = stop_strudel_tool_processes();
    let mut lock = active_process
        .lock()
        .map_err(|_| "Could not access Court Synth process lock.".to_string())?;
    if let Some(ref mut child) = *lock {
        if matches!(child.try_wait(), Ok(None)) {
            let installed = if score_changed {
                install_court_score_validated(cleaned)?
            } else {
                cleaned.to_string()
            };
            set_last_creative_artifact("court_synth", "court_synth/current_score.json");
            let parsed: serde_json::Value = serde_json::from_str(&installed).unwrap_or_default();
            let title = parsed
                .get("title")
                .and_then(|value| value.as_str())
                .unwrap_or("untitled CourtScore");
            return if score_changed {
                Ok(CourtSynthLaunchOutcome {
                    message: format!(
                        "Updated Court Synth project ‘{}’; the open workstation will hot-reload it.",
                        title
                    ),
                    score_changed: true,
                })
            } else {
                Ok(CourtSynthLaunchOutcome {
                    message: format!(
                        "Court Synth project ‘{}’ is already open; no musical change was installed.",
                        title
                    ),
                    score_changed: false,
                })
            };
        }
    }
    *lock = None;
    let installed = if score_changed {
        install_court_score_validated(cleaned)?
    } else {
        cleaned.to_string()
    };
    let mut command = Command::new(LOCAL_STRUDEL_PYTHON_PATH);
    command
        .arg(COURT_SYNTH_SCRIPT_PATH)
        .arg("open")
        .arg(COURT_SYNTH_SCORE_PATH)
        .arg("--geometry")
        .arg("1480x900+36+36")
        .arg("--play")
        .current_dir("D:\\Teledra")
        .stdout(Stdio::null())
        .stderr(Stdio::null());
    hide_console(&mut command);
    let child = match command.spawn() {
        Ok(child) => child,
        Err(error) => {
            if score_changed {
                if let Some(previous) = previous_score.as_deref() {
                    atomic_write_court_score(
                        Path::new(COURT_SYNTH_SCORE_PATH),
                        &normalized_court_score_code(previous),
                    )
                    .map_err(|rollback| {
                        format!(
                            "Could not launch Court Synth ({error}); score rollback also failed ({rollback})."
                        )
                    })?;
                }
            }
            return Err(format!(
                "Could not launch Court Synth: {error}. The previous score was preserved."
            ));
        }
    };
    *lock = Some(child);
    set_last_creative_artifact("court_synth", "court_synth/current_score.json");
    let parsed: serde_json::Value = serde_json::from_str(&installed).unwrap_or_default();
    let title = parsed
        .get("title")
        .and_then(|value| value.as_str())
        .unwrap_or("untitled CourtScore");
    Ok(CourtSynthLaunchOutcome {
        message: format!(
            "{}{}Loaded Court Synth project ‘{}’ — the single active music surface.",
            if stopped_legacy_python > 0 {
                "Retired Python Music Editor playback. "
            } else {
                ""
            },
            if stopped_legacy_strudel > 0 {
                "Retired Strudel playback. "
            } else {
                ""
            },
            title
        ),
        score_changed,
    })
}

fn launch_human_music_front_candidate(
    candidate: &str,
    ticket: &HumanMusicGenerationTicket,
    active_process: &Arc<std::sync::Mutex<Option<std::process::Child>>>,
) -> Result<CourtSynthLaunchOutcome, String> {
    validate_court_score_code(candidate)?;
    let current = std::fs::read_to_string(COURT_SYNTH_SCORE_PATH)
        .map_err(|error| format!("Could not re-read the live keeper: {error}"))?;
    if !court_score_establishes_new_identity(&current, candidate)? {
        return Err(
            "Front-stage exploration did not establish a genuinely new composition identity."
                .to_string(),
        );
    }
    if !court_score_has_meaningful_delta(candidate)? {
        return Err("Human-directed composer reply was a musical no-op.".to_string());
    }
    let (_, live_after_validation) = read_live_human_music_target()?;
    if !human_music_targets_match(&ticket.base, &live_after_validation) {
        return Err(
            "Score changed during feedback validation; stale candidate discarded.".to_string(),
        );
    }
    launch_court_synth_validated(candidate, active_process)
}

fn stop_court_synth(active_process: &Arc<std::sync::Mutex<Option<std::process::Child>>>) -> usize {
    let mut stopped = 0;
    if let Ok(mut lock) = active_process.lock() {
        if let Some(mut child) = lock.take() {
            let _ = child.kill();
            let _ = child.wait();
            stopped += 1;
        }
    }
    stopped + stop_tool_processes(&["court_synthesizer.py"], &["python.exe", "pythonw.exe"])
}

fn stop_tool_processes(markers: &[&str], allowed_process_names: &[&str]) -> usize {
    if markers.is_empty() || allowed_process_names.is_empty() {
        return 0;
    }
    let markers = markers
        .iter()
        .filter(|m| !m.trim().is_empty())
        .map(|m| format!("'{}'", m.replace('\'', "''").to_lowercase()))
        .collect::<Vec<_>>()
        .join(",");
    let names = allowed_process_names
        .iter()
        .filter(|n| !n.trim().is_empty())
        .map(|n| format!("'{}'", n.replace('\'', "''").to_lowercase()))
        .collect::<Vec<_>>()
        .join(",");
    if markers.is_empty() || names.is_empty() {
        return 0;
    }

    let script = format!(
        "$markers=@({}); $names=@({}); $self=$PID; $count=0; \
         Get-CimInstance Win32_Process | Where-Object {{ \
             $_.ProcessId -ne $self -and $_.CommandLine -and $_.Name -and \
             ($names -contains $_.Name.ToLowerInvariant()) \
         }} | ForEach-Object {{ \
             $cmd=$_.CommandLine.ToLowerInvariant(); $hit=$false; \
             foreach($m in $markers) {{ if($cmd -like \"*$m*\") {{ $hit=$true; break }} }} \
             if($hit) {{ Stop-Process -Id $_.ProcessId -Force -ErrorAction SilentlyContinue; $count++ }} \
         }}; $count",
        markers, names
    );

    let mut cmd = Command::new("powershell");
    cmd.arg("-NoProfile")
        .arg("-ExecutionPolicy")
        .arg("Bypass")
        .arg("-Command")
        .arg(script)
        .stdout(Stdio::piped())
        .stderr(Stdio::null());
    hide_console(&mut cmd);
    cmd.output()
        .ok()
        .and_then(|output| {
            String::from_utf8_lossy(&output.stdout)
                .trim()
                .parse::<usize>()
                .ok()
        })
        .unwrap_or(0)
}

fn publish_fractus_payload(payload: &serde_json::Value) -> Result<(), String> {
    let encoded = serde_json::to_vec(payload)
        .map_err(|error| format!("Failed to encode Fractus command: {error}"))?;
    let mut command = Command::new("D:\\Teledra\\.venv\\Scripts\\python.exe");
    command
        .arg("-c")
        .arg("import json,sys; from fractus_protocol import write_command_atomic; write_command_atomic(json.load(sys.stdin))")
        .current_dir("D:\\Teledra\\Fractus")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped());
    hide_console(&mut command);
    let mut child = command
        .spawn()
        .map_err(|error| format!("Failed to start Fractus command validator: {error}"))?;
    child
        .stdin
        .take()
        .ok_or_else(|| "Fractus command validator stdin was unavailable".to_string())?
        .write_all(&encoded)
        .map_err(|error| format!("Failed to send Fractus command: {error}"))?;
    let output = child
        .wait_with_output()
        .map_err(|error| format!("Fractus command validator failed: {error}"))?;
    if output.status.success() {
        Ok(())
    } else {
        let stderr = truncate_clean(&String::from_utf8_lossy(&output.stderr), 1_200);
        Err(if stderr.is_empty() {
            "Fractus command was rejected without a diagnostic".to_string()
        } else {
            format!("Fractus command rejected: {stderr}")
        })
    }
}

fn write_fractus_command(args: &[String]) -> Result<(), String> {
    let mut fractal_type = "mandala".to_string();
    let mut iterations = "180".to_string();
    let mut palette = "purple_haze".to_string();
    let mut c_real = "-0.7".to_string();
    let mut c_imag = "0.27015".to_string();
    let mut seed = "1".to_string();

    let mut i = 0;
    while i + 1 < args.len() {
        match args[i].as_str() {
            "--type" => fractal_type = args[i + 1].clone(),
            "--iterations" => iterations = args[i + 1].clone(),
            "--palette" => palette = args[i + 1].clone(),
            "--c-real" => c_real = args[i + 1].clone(),
            "--c-imag" => c_imag = args[i + 1].clone(),
            "--seed" => seed = args[i + 1].clone(),
            _ => {}
        }
        i += 2;
    }

    let payload = serde_json::json!({
        "schema_version": 1,
        "type": fractal_type,
        "iterations": iterations.parse::<u32>().map_err(|_| "invalid iteration payload")?,
        "palette": palette,
        "c_real": c_real.parse::<f64>().map_err(|_| "invalid c-real payload")?,
        "c_imag": c_imag.parse::<f64>().map_err(|_| "invalid c-imag payload")?,
        "seed": seed.parse::<u64>().map_err(|_| "invalid seed payload")?
    });
    publish_fractus_payload(&payload)
}

