        let reply = "Behold! [WORKSHOP_TOOL:\nmatrix_rain.py\nKIND: spawn\nPURPOSE: falling glyph rain\nVALUE: a hypnotic stream backdrop\nCODE:\n```python\nimport tkinter as tk\nr = tk.Tk()\nr.mainloop()\n```\n]";
