    #[test]
    fn startup_music_restore_policy_is_read_only_and_fail_closed() {
        let root = std::env::temp_dir().join(format!(
            "teledra_startup_music_restore_{}_{}",
            std::process::id(),
            current_unix_timestamp()
        ));
        std::fs::create_dir_all(&root).expect("create startup music test root");
        let score_path = root.join("current_score.json");
        let valid = default_court_score_code();
        std::fs::write(&score_path, &valid).expect("write valid CourtScore");

        let restored = existing_court_score_for_startup(&score_path, true, false)
            .expect("valid existing score should be selectable")
            .expect("valid existing score should be restored");
        assert_eq!(
            court_score_musical_fingerprint(&restored).expect("restored fingerprint"),
            court_score_musical_fingerprint(&valid).expect("source fingerprint")
        );
        assert_eq!(
            std::fs::read_to_string(&score_path).expect("score remains readable"),
            valid,
            "startup selection must not rewrite the project"
        );
        assert!(
            existing_court_score_for_startup(&score_path, false, false)
                .expect("disabled music should skip cleanly")
                .is_none()
        );
        assert!(
            existing_court_score_for_startup(&score_path, true, true)
                .expect("test mode should skip cleanly")
                .is_none()
        );

        let invalid = "{\"schema_version\":1,\"title\":\"broken\"}";
        std::fs::write(&score_path, invalid).expect("write invalid CourtScore");
        assert!(existing_court_score_for_startup(&score_path, true, false).is_err());
        assert_eq!(
            std::fs::read_to_string(&score_path).expect("invalid score remains readable"),
            invalid,
            "invalid startup state must be preserved for diagnosis"
        );
        std::fs::remove_file(&score_path).expect("remove score for missing-file case");
        assert!(
            existing_court_score_for_startup(&score_path, true, false)
                .expect("missing score should not bootstrap during startup")
                .is_none()
        );
        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn fractus_completion_requires_real_pixels_and_matching_hash() {
        use sha2::{Digest, Sha256};

        let root = std::env::temp_dir().join(format!(
            "teledra_fractus_evidence_{}_{}",
            std::process::id(),
            current_unix_timestamp()
        ));
        std::fs::create_dir_all(&root).expect("create evidence root");
        let output = root.join("render.png");
        let pixels = vec![12u8, 34, 56, 255, 78, 90, 123, 255];
        image::RgbaImage::from_raw(2, 1, pixels.clone())
            .expect("valid pixels")
            .save(&output)
            .expect("save image");
        let render_hash = format!("{:x}", Sha256::digest(&pixels));
        std::fs::write(
            root.join("render.png.json"),
            serde_json::json!({ "render_hash": render_hash }).to_string(),
        )
        .expect("save manifest");
        let status = serde_json::json!({
            "state": "completed",
            "render_hash": render_hash,
            "output_path": output,
            "width": 2,
            "height": 1
        });
        assert!(verify_fractus_completion_in(&status, &root).is_ok());

        let tampered = serde_json::json!({
            "state": "completed",
            "render_hash": "0".repeat(64),
            "output_path": root.join("render.png"),
            "width": 2,
            "height": 1
        });
        assert!(verify_fractus_completion_in(&tampered, &root).is_err());
        let _ = std::fs::remove_dir_all(root);
    }

    #[test]
    fn taste_desire_tags_are_hidden_and_structured() {
        let reply = "The slower pulse feels better. [TASTE: like|dungeon synth|it feels atmospheric|0.8] [DESIRE: build a lo-fi room|immediate|0.7]";
        let (cleaned, events) = extract_taste_desire_tags(reply, "test:fixture");
        assert_eq!(cleaned, "The slower pulse feels better.");
        assert_eq!(events.len(), 2);
        assert_eq!(events[0]["type"], "like");
        assert_eq!(events[0]["subject"], "dungeon synth");
        assert_eq!(events[1]["type"], "desire");
        assert_eq!(events[1]["want"], "build a lo-fi room");
    }

    #[test]
    fn court_score_extraction_tolerates_fumbled_tag_grammar() {
        // Observed in production: qwen drops the opening '[' or the trailing
        // ']' and every composition was discarded over punctuation. The JSON
        // is brace-matched and fully validated downstream, so extraction is
        // lenient about the tag shell.
        let payload = r#"{"title": "Test", "bpm": 90}"#;

        // 1. Properly bracketed still works and is removed cleanly.
        let bracketed = format!("Behold! [COURT_SCORE: {payload} ] A triumph.");
        let (cleaned, json) = extract_court_score_tag(&bracketed).expect("bracketed");
        assert_eq!(json, payload);
        assert_eq!(cleaned, "Behold!  A triumph.");

        // 2. Missing trailing ']' no longer discards a perfect payload.
        let unclosed = format!("Behold! [COURT_SCORE: {payload}");
        let (_, json) = extract_court_score_tag(&unclosed).expect("unclosed");
        assert_eq!(json, payload);

        // 3. Bare marker with no brackets at all (the common failure).
        let bare = format!("COURT_SCORE: {payload}");
        let (_, json) = extract_court_score_tag(&bare).expect("bare");
        assert_eq!(json, payload);

        // 4. Prose that mentions the tag mid-word must not be consumed.
        assert!(extract_court_score_tag("myCOURT_SCORE: notes about scoring").is_none());
        // 5. Marker with no JSON object yields nothing.
        assert!(extract_court_score_tag("COURT_SCORE: I shall compose later!").is_none());
    }

    #[test]
    fn taste_extraction_strips_leaked_labels_and_strengths() {
        // Real failure shapes observed in knowledge/taste_desire.json: the model
        // leaks the field-label word into the payload, appends a bare strength
        // with no '|' separator, or emits a bare label with no content at all.
        let reply = "Hm. [CURIOSITY: question What could possibly be the use of such fragile grandeur? 0.7] [CURIOSITY: question] [DESIRE: want to map the vaults 0.8]";
        let (cleaned, events) = extract_taste_desire_tags(reply, "test:fixture");
        assert_eq!(cleaned, "Hm.");
        // the degenerate bare-label curiosity is dropped entirely; extraction
        // emits per-prefix order (DESIRE before CURIOSITY), not document order
        assert_eq!(events.len(), 2);
        assert_eq!(events[0]["want"], "to map the vaults");
        assert!((events[0]["strength"].as_f64().unwrap() - 0.8).abs() < 1e-6);
        assert_eq!(
            events[1]["question"],
            "What could possibly be the use of such fragile grandeur?"
        );
        // word-boundary safety: a real word starting with a label is untouched
        let (_, safe) = extract_taste_desire_tags("[DESIRE: wanting more velvet]", "t");
        assert_eq!(safe[0]["want"], "wanting more velvet");
    }

