    #[test]
    fn broadcast_clock_is_single_chain_bounded_and_deterministic() {
        let first = broadcast_interval_seconds("adaptive security", 17);
        assert_eq!(first, broadcast_interval_seconds("adaptive security", 17));
        let intervals = (0..128)
            .map(|index| broadcast_interval_seconds("adaptive security", index))
            .collect::<Vec<_>>();
        assert!(intervals.iter().all(|seconds| {
            (BROADCAST_MIN_TURN_INTERVAL_SECS..=BROADCAST_MAX_TURN_INTERVAL_SECS).contains(seconds)
        }));
        assert!(intervals.iter().any(|seconds| *seconds != first));
        assert_eq!(format_broadcast_clock(0), "00:00");
        assert_eq!(format_broadcast_clock(60 * 60 + 37 * 60), "01:37");
        assert_eq!(format_broadcast_countdown(142), "02:22");
    }

    #[test]
    fn broadcast_rundown_has_exact_two_hour_boundaries() {
        assert_eq!(broadcast_rundown_index(0), 0);
        assert_eq!(broadcast_rundown_index(599), 0);
        assert_eq!(broadcast_rundown_index(600), 1);
        assert_eq!(broadcast_rundown_index(1_500), 2);
        assert_eq!(broadcast_rundown_index(2_400), 3);
        assert_eq!(broadcast_rundown_index(3_600), 4);
        assert_eq!(broadcast_rundown_index(4_800), 5);
        assert_eq!(broadcast_rundown_index(6_000), 6);
        assert_eq!(broadcast_rundown_index(6_900), 7);
        assert_eq!(broadcast_rundown_index(7_199), 7);

        let now = Instant::now();
        let session = BroadcastSession::new(9, "a precise topic".to_string(), now);
        assert_eq!(session.deadline.duration_since(now).as_secs(), 7_200);
        let rundown = broadcast_rundown_text("a precise topic");
        for marker in [
            "00:00", "00:10", "00:25", "00:40", "01:00", "01:20", "01:40", "01:55",
        ] {
            assert!(rundown.contains(marker));
        }
    }

