    #[test]
    fn broadcast_state_hands_exact_panel_text_back_to_teledra() {
        let now = Instant::now();
        let mut session = BroadcastSession::new(23, "adaptive security".to_string(), now);
        let opening = build_broadcast_ticket(&mut session, now);
        assert_eq!(opening.kind, BroadcastTurnKind::HostOpening);
        let host_claim = "Static walls fail when an attacker can learn. Delegates, what say you?";
        accept_broadcast_contribution(&mut session, &opening, host_claim, now);
        assert_eq!(session.next_kind, BroadcastTurnKind::Counterpoint);

        session.awaiting_speech = false;
        let counterpoint = build_broadcast_ticket(&mut session, now + Duration::from_secs(90));
        assert_eq!(counterpoint.kind, BroadcastTurnKind::Counterpoint);
        assert_eq!(counterpoint.prior_text, host_claim);
        let panel_text = "However, adaptation without trustworthy observation merely lets the defender automate the wrong belief; the difficult question is which signals remain expensive for an attacker to imitate.";
        accept_broadcast_contribution(
            &mut session,
            &counterpoint,
            panel_text,
            now + Duration::from_secs(90),
        );
        assert_eq!(session.panelists_in_segment, 1);
        assert!(session.panelists_in_segment <= BROADCAST_MAX_PANELISTS_PER_SEGMENT);
        assert_eq!(session.next_kind, BroadcastTurnKind::HostReaction);

        session.awaiting_speech = false;
        let reaction = build_broadcast_ticket(&mut session, now + Duration::from_secs(180));
        assert_eq!(reaction.kind, BroadcastTurnKind::HostReaction);
        assert_eq!(reaction.role, CourtRole::Queen);
        assert_eq!(reaction.prior_text, panel_text);
        assert_eq!(reaction.prior_speaker, counterpoint.role.as_str());
        accept_broadcast_contribution(
            &mut session,
            &reaction,
            "Alchemist, your observation problem bites. The next question is how a defense prices uncertainty without paralyzing itself.",
            now + Duration::from_secs(180),
        );
        assert_eq!(session.panelists_in_segment, 0);
        assert!(session.pending_panel.is_none());
    }

