    #[test]
    fn fallback_styles_have_distinct_developed_forms() {
        let scores: Vec<serde_json::Value> = (0..3)
            .map(|variant| {
                let code = court_score_variant_code(variant, 41 + variant as u64, "test");
                validate_court_score_code(&code)
                    .expect("every fallback style must pass the active CourtScore gate");
                serde_json::from_str(&code).unwrap()
            })
            .collect();
        let plans: Vec<String> = scores
            .iter()
            .map(|score| score["sections"].to_string())
            .collect();
        assert_ne!(plans[0], plans[1]);
        assert_ne!(plans[1], plans[2]);
        assert_ne!(plans[0], plans[2]);
        for score in scores {
            let sections = score["sections"].as_array().unwrap();
            let energies: Vec<f64> = sections
                .iter()
                .map(|section| section["energy"].as_f64().unwrap())
                .collect();
            let transforms: std::collections::HashSet<&str> = sections
                .iter()
                .map(|section| section["transform"].as_str().unwrap())
                .collect();
            let has_release = energies.windows(2).any(|pair| pair[0] - pair[1] >= 0.20);
            let span = energies.iter().copied().fold(f64::NEG_INFINITY, f64::max)
                - energies.iter().copied().fold(f64::INFINITY, f64::min);
            assert!(span >= 0.40, "fallback form needs a real energy arc");
            assert!(has_release, "fallback form needs subtraction after a rise");
            assert!(
                transforms.len() >= 4,
                "fallback form needs motif development"
            );
        }
    }

    #[test]
    fn fallback_fleet_has_nine_distinct_valid_musical_plans() {
        let mut fingerprints = std::collections::HashSet::new();
        for variant in 0..9 {
            let code = court_score_variant_code(variant, 900 + variant as u64, "novelty_test");
            validate_court_score_code(&code)
                .unwrap_or_else(|error| panic!("fallback variant {variant} failed: {error}"));
            let score: serde_json::Value = serde_json::from_str(&code).unwrap();
            let (min_bpm, max_bpm, expected_mode, expected_chords) =
                match score["style"].as_str().unwrap() {
                    "spicy_lofi" => (
                        72,
                        98,
                        "natural_minor",
                        serde_json::json!(["Em9", "Cmaj9", "Am9", "B7", "Em9", "Am9", "B7", "Em"]),
                    ),
                    "court_experimental" => (
                        88,
                        116,
                        "dorian",
                        serde_json::json!(["Dm", "G", "Cmaj7", "A7", "Dm", "G", "A7", "Dm"]),
                    ),
                    _ => (
                        100,
                        128,
                        "natural_minor",
                        serde_json::json!(["Dm", "Bb", "Gm", "A7", "Dm", "Bb", "A7", "Dm"]),
                    ),
                };
            let bpm = score["transport"]["bpm"].as_u64().unwrap();
            assert!((min_bpm..=max_bpm).contains(&bpm));
            assert_eq!(score["harmony"]["mode"], expected_mode);
            assert_eq!(score["harmony"]["chords"], expected_chords);
            let sections = score["sections"].as_array().unwrap();
            assert_eq!(
                sections
                    .iter()
                    .map(|section| section["bars"].as_u64().unwrap())
                    .sum::<u64>(),
                64
            );
            let bpm = score["transport"]["bpm"].as_f64().unwrap();
            let seconds = 64.0 * 4.0 * 60.0 / bpm;
            assert!(
                seconds >= 120.0,
                "fallback must run for at least two minutes"
            );
            assert!(
                sections
                    .iter()
                    .all(|section| matches!(section["bars"].as_u64(), Some(4) | Some(8)))
            );
            assert!(
                fingerprints.insert(court_score_musical_fingerprint(&code).unwrap()),
                "fallback variant {variant} repeated an earlier musical plan"
            );
        }
        assert_eq!(fingerprints.len(), 9);
    }

    #[test]
    fn court_score_delta_ignores_identity_but_detects_audible_change() {
        let base = default_court_score_code();
        let mut relabeled: serde_json::Value = serde_json::from_str(&base).unwrap();
        relabeled["revision"] = serde_json::json!(999);
        relabeled["title"] = serde_json::json!("Only a new label");
        relabeled["manual_notes"] = serde_json::json!([
            {"track":"lead","beat":1.0,"duration":0.5,"pitch":"D4","velocity":0.7}
        ]);
        relabeled["lineage"] = serde_json::json!({"source":"test"});
        let relabeled = serde_json::to_string(&relabeled).unwrap();
        assert_eq!(
            court_score_musical_fingerprint(&base).unwrap(),
            court_score_musical_fingerprint(&relabeled).unwrap()
        );

        let mut reseeded: serde_json::Value = serde_json::from_str(&base).unwrap();
        reseeded["seed"] = serde_json::json!(123456789_u64);
        let reseeded = serde_json::to_string(&reseeded).unwrap();
        assert_eq!(
            court_score_musical_fingerprint(&base).unwrap(),
            court_score_musical_fingerprint(&reseeded).unwrap(),
            "micro-humanization seed alone must not masquerade as a composition"
        );

        let mut changed: serde_json::Value = serde_json::from_str(&base).unwrap();
        let current_bpm = changed["transport"]["bpm"].as_u64().unwrap();
        changed["transport"]["bpm"] = serde_json::json!(if current_bpm == 96 { 88 } else { 96 });
        let changed = serde_json::to_string(&changed).unwrap();
        assert_ne!(
            court_score_musical_fingerprint(&base).unwrap(),
            court_score_musical_fingerprint(&changed).unwrap()
        );
    }

