    #[test]
    fn feedback_decisions_have_bounded_identity_semantics() {
        assert!(!HumanMusicFeedbackDecision::LikeAsIs.requests_work());
        assert!(HumanMusicFeedbackDecision::LikeWorkOnIt.requests_work());
        assert!(HumanMusicFeedbackDecision::LikeWorkOnIt.preserves_keeper_identity());
        assert!(HumanMusicFeedbackDecision::LikeWorkOnIt.routes_to_back_workshop());
        assert!(!HumanMusicFeedbackDecision::LikeWorkOnIt.starts_keeper_lease());
        assert!(HumanMusicFeedbackDecision::DislikeWorkOnIt.preserves_keeper_identity());
        assert!(HumanMusicFeedbackDecision::DislikeWorkOnIt.routes_to_back_workshop());
        assert!(HumanMusicFeedbackDecision::Dislike.requests_work());
        assert!(!HumanMusicFeedbackDecision::Dislike.preserves_keeper_identity());
        assert!(HumanMusicFeedbackDecision::LikeAsIs.starts_keeper_lease());
    }

    #[test]
    fn like_as_is_lease_blocks_before_but_not_at_ten_minute_boundary() {
        let target = HumanMusicScoreTarget {
            project_id: "keeper".to_string(),
            score_revision: 12,
            score_sha256: "d".repeat(64),
        };
        let mut feedback = feedback_fixture(&target, HumanMusicFeedbackDecision::LikeAsIs);
        feedback.created_at_unix_ns = 1_000_000_000_000;
        let deadline = human_music_feedback_lease_expires_unix_ns(&feedback)
            .expect("like-as-is must establish a bounded lease");
        assert_eq!(
            deadline,
            feedback.created_at_unix_ns + HUMAN_MUSIC_KEEPER_LEASE_SECS * NANOS_PER_SECOND
        );
        let mut state = HumanMusicFeedbackState {
            hold: Some(HumanMusicHold {
                event_id: feedback.event_id.clone(),
                decision: feedback.decision,
                target: target.clone(),
                awaiting_review: false,
                lease_expires_unix_ns: deadline,
            }),
            latest_feedback: Some(feedback),
            ..HumanMusicFeedbackState::default()
        };

        assert!(human_music_hold_blocks_target_at(
            &state,
            &target,
            deadline - 1
        ));
        assert!(!human_music_hold_blocks_target_at(
            &state, &target, deadline
        ));

        state.hold.as_mut().unwrap().awaiting_review = true;
        assert!(human_music_hold_blocks_target_at(
            &state,
            &target,
            deadline + NANOS_PER_SECOND
        ));
    }

    #[test]
    fn final_install_gate_reads_live_like_event_but_releases_it_at_lease_expiry() {
        let target = HumanMusicScoreTarget {
            project_id: "keeper".to_string(),
            score_revision: 12,
            score_sha256: "d".repeat(64),
        };
        let mut feedback = feedback_fixture(&target, HumanMusicFeedbackDecision::LikeAsIs);
        feedback.created_at_unix_ns = 9_000_000_000_000;
        let deadline = human_music_feedback_lease_expires_unix_ns(&feedback).unwrap();
        let state = HumanMusicFeedbackState::default();

        assert!(human_music_feedback_blocks_autonomous_install_at(
            &state,
            &target,
            Some(&feedback),
            deadline - 1,
        ));
        assert!(!human_music_feedback_blocks_autonomous_install_at(
            &state,
            &target,
            Some(&feedback),
            deadline,
        ));

        let mut newer_target = target.clone();
        newer_target.score_revision += 1;
        assert!(!human_music_feedback_blocks_autonomous_install_at(
            &state,
            &newer_target,
            Some(&feedback),
            deadline - 1,
        ));
    }

    #[test]
    fn human_music_tickets_reject_stale_and_superseded_replies() {
        let target = HumanMusicScoreTarget {
            project_id: "keeper".to_string(),
            score_revision: 12,
            score_sha256: "d".repeat(64),
        };
        let feedback = feedback_fixture(&target, HumanMusicFeedbackDecision::DislikeWorkOnIt);
        let ticket = HumanMusicGenerationTicket {
            event_id: feedback.event_id.clone(),
            epoch: 4,
            decision: feedback.decision,
            base: target.clone(),
        };
        let mut state = HumanMusicFeedbackState {
            epoch: 4,
            pending: Some(feedback),
            hold: Some(HumanMusicHold {
                event_id: ticket.event_id.clone(),
                decision: ticket.decision,
                target: target.clone(),
                awaiting_review: false,
                lease_expires_unix_ns: 0,
            }),
            ..HumanMusicFeedbackState::default()
        };
        assert!(human_music_ticket_is_current(&state, &ticket, &target));
        assert!(!human_music_hold_blocks_target(&state, &target));
        state.hold.as_mut().unwrap().awaiting_review = true;
        assert!(human_music_hold_blocks_target(&state, &target));

        let mut stale = target.clone();
        stale.score_revision += 1;
        assert!(!human_music_ticket_is_current(&state, &ticket, &stale));
        state.epoch += 1;
        assert!(!human_music_ticket_is_current(&state, &ticket, &target));
    }

    #[test]
    fn back_workshop_prompt_is_exact_off_air_and_identity_bound() {
        let base = r#"{"schema_version":1,"title":"Keeper — exact","motif":["E5"]}"#;
        let parent = r#"{"schema_version":1,"title":"Keeper — pass one","motif":["E5"]}"#;
        let ticket = HumanMusicWorkshopTicket {
            event_id: format!("music-feedback-{}", "e".repeat(64)),
            decision: HumanMusicFeedbackDecision::LikeWorkOnIt,
            pass_index: 2,
            attempt: 1,
            fallback_used: false,
            planned_passes: 4,
            focus: "groove_and_pulse".to_string(),
            objective: "Strengthen the exact pocket without changing identity.".to_string(),
            base_score_sha256: sha256_hex(base.as_bytes()),
            parent_score_sha256: sha256_hex(parent.as_bytes()),
            base_score: base.to_string(),
            parent_score: parent.to_string(),
        };
        let prompt = human_music_workshop_prompt(&ticket);
        assert!(prompt.contains(base));
        assert!(prompt.contains(parent));
        assert!(prompt.contains("pass 2/4"));
        assert!(prompt.contains("groove_and_pulse"));
        assert!(prompt.contains("live Court Synth project may now be a different song"));
        assert!(prompt.contains("generate a new random `seed` AND you MUST change `sections`"));
        assert!(prompt.contains("preserve `mix` and `track_mix` byte-for-byte"));
        assert!(prompt.contains("Do not claim playback, installation, or success"));

        let mut mix_ticket = ticket;
        mix_ticket.pass_index = 4;
        mix_ticket.focus = "mix_and_loop".to_string();
        let mix_prompt = human_music_workshop_prompt(&mix_ticket);
        assert!(mix_prompt.contains("change `mix` and/or `track_mix`"));
        assert!(mix_prompt.contains("preserve `seed` and `sections` byte-for-byte"));
    }

