    #[test]
    fn fractus_live_failure_runs_one_safe_fallback_without_creation_credit() {
        let mut calls = Vec::new();
        let recovered = execute_fractus_live_with_fallback(
            "not valid live code",
            "artist",
            |script, source| {
                calls.push((script.to_string(), source.to_string()));
                if calls.len() == 1 {
                    Err("primary rejected".to_string())
                } else {
                    Ok("fallback verified".to_string())
                }
            },
        );
        assert_eq!(calls.len(), 2, "failure must trigger exactly one recovery");
        assert_eq!(calls[1].0, FRACTUS_SAFE_V2_FALLBACK);
        assert!(calls[1].1.ends_with("_runtime_recovery"));
        assert!(matches!(
            &recovered,
            FractusLiveExecution::RuntimeRecovered { .. }
        ));
        assert!(!recovered.earns_creation_credit());

        let mut failed_calls = 0usize;
        let failed = execute_fractus_live_with_fallback("bad", "artist", |_, _| {
            failed_calls += 1;
            Err(format!("failure {failed_calls}"))
        });
        assert_eq!(failed_calls, 2, "recovery must never recurse");
        assert!(matches!(&failed, FractusLiveExecution::Failed { .. }));
        assert!(!failed.earns_creation_credit());

        let mut success_calls = 0usize;
        let authored = execute_fractus_live_with_fallback("valid", "artist", |_, _| {
            success_calls += 1;
            Ok("verified".to_string())
        });
        assert_eq!(success_calls, 1, "valid art must not launch the fallback");
        assert!(authored.earns_creation_credit());
    }

